#!/usr/bin/env python3"""NICTO Super Training Pipeline v3.0 ΓÇö Multi-Stage Training for Frontier IntelligenceTrains NICTO to surpass GPT-5.5, Claude Sonnet 5, Gemini 3.1 Pro, and DeepSeek V4using a comprehensive multi-stage pipeline:Stage 1: Supervised Fine-Tuning (SFT) on 1M+ high-quality examplesStage 2: Reward Model Training from human preferencesStage 3: RLHF (PPO) alignment with KL penaltyStage 4: Direct Preference Optimization (DPO) for efficient alignment  Stage 5: Group Relative Policy Optimization (GRPO) for reasoning tasksStage 6: Curriculum-based progressive training (easy ΓåÆ expert)Stage 7: Continuous improvement loop (auto-detect weaknesses ΓåÆ fine-tune)Supported models:  - DeepSeek V4 (671B MoE, 37B active)  - Llama 405B Instruct  - Qwen 2.5-72B Instruct  - Qwen 2.5-32B Instruct (for more modest hardware)  - Mistral Large 2 (123B)  - Gemma 2 27B  Modes:  - cpu: Train tiny models locally for proof-of-concept  - cloud: Generate optimized training scripts for cloud GPU (RunPod, Lambda, Colab)  - sft: Supervised fine-tuning only  - rlhf: Full SFT ΓåÆ Reward Model ΓåÆ PPO pipeline  - dpo: Direct Preference Optimization  - grpo: Group Relative Policy Optimization (for math/reasoning)  - curriculum: Progressive training from easy ΓåÆ expert  - continuous: Full auto-improvement loop"""import jsonimport mathimport osimport randomimport sysimport timeimport warningsfrom pathlib import Pathfrom typing import Any, Dict, List, Optional, Tuplewarnings.filterwarnings("ignore", category=UserWarning)HERE = Path(__file__).parentOUTPUT_DIR = HERE / "nicto_outputs" / "models"REPORT_DIR = HERE / "nicto_outputs" / "reports"CLOUD_DIR = HERE / "nicto_outputs" / "cloud_scripts"LOG_DIR = HERE / "nicto_outputs" / "training_logs"# ΓöÇΓöÇΓöÇ Model Registry ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇFRONTIER_MODELS = {    "deepseek-v4": {        "name": "DeepSeek V4",        "repo": "deepseek-ai/DeepSeek-V4",        "params": "671B (MoE, 37B active)",        "min_vram_gb": 80,        "tier": "frontier",        "description": "Best open-weight model. Hybrid CSA+HCA attention, DeepSeekMoE, mHC connections.",        "lora_target_modules": ["q_proj", "k_proj", "v_proj", "o_proj", "gate_proj", "up_proj", "down_proj"],    },    "llama-405b": {        "name": "Llama 3.1 405B",        "repo": "meta-llama/Meta-Llama-3.1-405B-Instruct",        "params": "405B (dense)",        "min_vram_gb": 80,        "tier": "frontier",        "description": "Meta's largest model, strong across all benchmarks.",        "lora_target_modules": ["q_proj", "k_proj", "v_proj", "o_proj", "gate_proj", "up_proj", "down_proj"],    },    "qwen-72b": {        "name": "Qwen 2.5 72B",        "repo": "Qwen/Qwen2.5-72B-Instruct",        "params": "72B (dense)",        "min_vram_gb": 48,        "tier": "high",        "description": "Strong open-weight model, excellent multilingual performance.",        "lora_target_modules": ["q_proj", "k_proj", "v_proj", "o_proj", "gate_proj", "up_proj", "down_proj"],    },    "qwen-32b": {        "name": "Qwen 2.5 32B",        "repo": "Qwen/Qwen2.5-32B-Instruct",        "params": "32B (dense)",        "min_vram_gb": 24,        "tier": "medium",        "description": "Good balance of performance and VRAM requirements.",        "lora_target_modules": ["q_proj", "k_proj", "v_proj", "o_proj", "gate_proj", "up_proj", "down_proj"],    },    "mistral-large": {        "name": "Mistral Large 2",        "repo": "mistralai/Mistral-Large-2",        "params": "123B (dense)",        "min_vram_gb": 64,        "tier": "high",        "description": "Excellent reasoning and multilingual capabilities.",        "lora_target_modules": ["q_proj", "k_proj", "v_proj", "o_proj", "gate_proj", "up_proj", "down_proj"],    },    "gemma-27b": {        "name": "Gemma 2 27B",        "repo": "google/gemma-2-27b-it",        "params": "27B (dense)",        "min_vram_gb": 20,        "tier": "medium",        "description": "Google's open model, strong on academic benchmarks.",        "lora_target_modules": ["q_proj", "k_proj", "v_proj", "o_proj", "gate_proj", "up_proj", "down_proj"],    },}# ΓöÇΓöÇΓöÇ Training Configuration ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇDEFAULT_CONFIG = {    "base_model": "Qwen/Qwen2.5-32B-Instruct",    "max_seq_length": 8192,    "lora_r": 32,    "lora_alpha": 64,    "lora_dropout": 0.0,    "per_device_batch_size": 2,    "gradient_accumulation_steps": 8,    "learning_rate": 2e-4,    "num_train_epochs": 3,    "warmup_steps": 20,    "weight_decay": 0.01,    "lr_scheduler_type": "cosine",    "optim": "adamw_8bit",    "seed": 42,    "use_rslora": True,    "use_gradient_checkpointing": True,    "load_in_4bit": True,    "bf16": True,    "fp16": False,}# ΓöÇΓöÇΓöÇ SFT Training Script Generator ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef generate_sft_script(model_config: Dict, data_path: str, output_path: str) -> str:    """Generate optimized SFT training script using Unsloth."""        return f'''#!/usr/bin/env python3"""NICTO Super Training v3.0 ΓÇö Stage 1: Supervised Fine-TuningAuto-generated by train_super_v3.py"""import json, os, torch, sysos.environ["TOKENIZERS_PARALLELISM"] = "false"os.environ["HF_HUB_ENABLE_HF_TRANSFER"] = "1"# ΓöÇΓöÇΓöÇ Config ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇBASE_MODEL = "{model_config["base_model"]}"DATA_PATH = "{data_path.replace(chr(92), '/')}"OUTPUT_DIR = "{output_path.replace(chr(92), '/')}"MAX_SEQ_LENGTH = {model_config["max_seq_length"]}LORA_R = {model_config["lora_r"]}LORA_ALPHA = {model_config["lora_alpha"]}BATCH_SIZE = {model_config["per_device_batch_size"]}GRAD_ACCUM = {model_config["gradient_accumulation_steps"]}LR = {model_config["learning_rate"]}EPOCHS = {model_config["num_train_epochs"]}# ΓöÇΓöÇΓöÇ Load Data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇprint(f"Loading training data from {{DATA_PATH}}...")with open(DATA_PATH, "r", encoding="utf-8") as f:    raw_data = [json.loads(line) for line in f if line.strip()]print(f"Loaded {{len(raw_data)}} training examples.")# ΓöÇΓöÇΓöÇ Unsloth Setup ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇfrom unsloth import FastLanguageModel, is_bfloat16_supportedfrom unsloth.chat_templates import get_chat_template, train_on_responses_onlyfrom datasets import Datasetfrom transformers import TrainingArgumentsfrom trl import SFTTrainerdtype = torch.bfloat16 if is_bfloat16_supported() else torch.float16model, tokenizer = FastLanguageModel.from_pretrained(    model_name=BASE_MODEL,    max_seq_length=MAX_SEQ_LENGTH,    dtype=dtype,    load_in_4bit=True,)tokenizer = get_chat_template(tokenizer, chat_template="chatml")model = FastLanguageModel.get_peft_model(    model,    r=LORA_R,    target_modules=["q_proj", "k_proj", "v_proj", "o_proj",                    "gate_proj", "up_proj", "down_proj"],    lora_alpha=LORA_ALPHA,    lora_dropout=0,    bias="none",    use_gradient_checkpointing="unsloth",    random_state=42,    use_rslora=True,    loftq_config=None,)print(f"Model loaded: {{BASE_MODEL}}")print(f"Trainable params: {{sum(p.numel() for p in model.parameters() if p.requires_grad)}}")# ΓöÇΓöÇΓöÇ Format Dataset ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef format_func(examples):    texts = []    for msg_list in examples["messages"]:        text = ""        for msg in msg_list:            role = msg["role"]            content = msg["content"]            text += f"<|im_start|>{{role}}\\n{{content}}<|im_end|>\\n"        text += "<|im_start|>assistant\\n"        texts.append(text)    return {{"text": texts}}dataset = Dataset.from_list(raw_data)dataset = dataset.map(format_func, batched=True)print(f"Dataset: {{len(dataset)}} examples")# ΓöÇΓöÇΓöÇ Train ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇtrainer = SFTTrainer(    model=model,    tokenizer=tokenizer,    train_dataset=dataset,    dataset_text_field="text",    max_seq_length=MAX_SEQ_LENGTH,    dataset_num_proc=4,    packing=False,    args=TrainingArguments(        per_device_train_batch_size=BATCH_SIZE,        gradient_accumulation_steps=GRAD_ACCUM,        warmup_steps=20,        num_train_epochs=EPOCHS,        learning_rate=LR,        fp16=not is_bfloat16_supported(),        bf16=is_bfloat16_supported(),        logging_steps=1,        optim="adamw_8bit",        weight_decay=0.01,        lr_scheduler_type="cosine",        seed=42,        output_dir=OUTPUT_DIR,        report_to="none",        save_strategy="epoch",        eval_strategy="no",        save_total_limit=3,        ddp_find_unused_parameters=False,        dataloader_num_workers=4,    ),)trainer = train_on_responses_only(    trainer,    instruction_part="<|im_start|>user\\n",    response_part="<|im_start|>assistant\\n",)print("\\n=== STARTING SFT TRAINING ===")trainer_stats = trainer.train()final_loss = trainer_stats.training_lossprint(f"\\n=== SFT COMPLETE ===")print(f"  Model: {{BASE_MODEL}}")print(f"  Examples: {{len(raw_data)}}")print(f"  Epochs: {{EPOCHS}}")print(f"  Final loss: {{final_loss:.4f}}")# Save LoRA adaptersmodel.save_pretrained(OUTPUT_DIR)tokenizer.save_pretrained(OUTPUT_DIR)print(f"LoRA adapters saved to {{OUTPUT_DIR}}")# Save mergedmerge_path = OUTPUT_DIR + "_merged"model.save_pretrained_merged(merge_path, tokenizer)print(f"Merged model saved to {{merge_path}}")# Export GGUFgguf_path = OUTPUT_DIR + "_gguf"model.save_pretrained_gguf(gguf_path, tokenizer, quantization_method="q4_k_m")print(f"GGUF model saved to {{gguf_path}}")'''def generate_dpo_script(model_config: Dict, data_path: str, output_path: str) -> str:    """Generate DPO (Direct Preference Optimization) training script."""        # Normalize paths for Windows compatibility    data_path_norm = data_path.replace("\\", "/")    output_path_norm = output_path.replace("\\", "/")        return f'''#!/usr/bin/env python3"""NICTO Super Training v3.0 ΓÇö Stage 4: Direct Preference OptimizationDPO aligns the model to human preferences without explicit reward modeling."""import json, os, random, torchos.environ["TOKENIZERS_PARALLELISM"] = "false"BASE_MODEL = "{output_path_norm}_merged"  # Load from SFT checkpointDATA_PATH = "{data_path_norm}"OUTPUT_DIR = "{output_path_norm}_dpo"MAX_SEQ_LENGTH = {model_config["max_seq_length"]}LORA_R = {model_config["lora_r"]}BATCH_SIZE = {model_config["per_device_batch_size"]}GRAD_ACCUM = {model_config["gradient_accumulation_steps"]}LR = 5e-6  # Lower LR for DPOEPOCHS = 2# Load datawith open(DATA_PATH, "r") as f:    raw_data = [json.loads(line) for line in f if line.strip()]    # Convert to DPO format: each example needs "chosen" and "rejected" messagesdpo_data = []for item in raw_data:    # For DPO we pair good responses with weaker ones    # Here we use the training data as "chosen" and generate a "rejected" variant    if random.random() < 0.5:        dpo_data.append({{            "chosen": item["messages"],            "rejected": item["messages"][:-1] + [{{"role": "assistant", "content": "I don't know the answer to that question."}}],        }})from unsloth import FastLanguageModel, is_bfloat16_supportedfrom datasets import Datasetfrom trl import DPOTrainerfrom transformers import TrainingArgumentsmodel, tokenizer = FastLanguageModel.from_pretrained(    model_name=BASE_MODEL,    max_seq_length=MAX_SEQ_LENGTH,    dtype=torch.bfloat16 if is_bfloat16_supported() else torch.float16,    load_in_4bit=True,)model = FastLanguageModel.get_peft_model(    model,    r=LORA_R,    target_modules=["q_proj", "k_proj", "v_proj", "o_proj",                    "gate_proj", "up_proj", "down_proj"],    lora_alpha=64,    lora_dropout=0,    bias="none",    use_gradient_checkpointing="unsloth",    random_state=42,)dataset = Dataset.from_list(dpo_data)trainer = DPOTrainer(    model=model,    ref_model=None,    tokenizer=tokenizer,    train_dataset=dataset,    args=TrainingArguments(        per_device_train_batch_size=BATCH_SIZE,        gradient_accumulation_steps=GRAD_ACCUM,        warmup_steps=10,        num_train_epochs=EPOCHS,        learning_rate=LR,        fp16=not is_bfloat16_supported(),        bf16=is_bfloat16_supported(),        logging_steps=1,        optim="adamw_8bit",        seed=42,        output_dir=OUTPUT_DIR,        report_to="none",    ),    beta=0.1,    max_prompt_length=MAX_SEQ_LENGTH // 2,    max_length=MAX_SEQ_LENGTH,)print("\\n=== STARTING DPO TRAINING ===")trainer.train()model.save_pretrained(OUTPUT_DIR)tokenizer.save_pretrained(OUTPUT_DIR)print(f"DPO model saved to {{OUTPUT_DIR}}")'''def generate_grpo_script(model_config: Dict, output_path: str) -> str:    """Generate GRPO (Group Relative Policy Optimization) script for reasoning."""        return f'''#!/usr/bin/env python3"""NICTO Super Training v3.0 ΓÇö Stage 5: Group Relative Policy OptimizationGRPO enhances reasoning by comparing multiple sampled responses within a group."""import torch, mathfrom unsloth import FastLanguageModel, is_bfloat16_supportedBASE_MODEL = "{output_path.replace(chr(92), '/')}_merged"OUTPUT_DIR = "{output_path.replace(chr(92), '/')}_grpo"MAX_SEQ_LENGTH = {model_config["max_seq_length"]}model, tokenizer = FastLanguageModel.from_pretrained(    model_name=BASE_MODEL,    max_seq_length=MAX_SEQ_LENGTH,    dtype=torch.bfloat16 if is_bfloat16_supported() else torch.float16,    load_in_4bit=True,)model = FastLanguageModel.get_peft_model(    model, r=32,    target_modules=["q_proj", "k_proj", "v_proj", "o_proj",                    "gate_proj", "up_proj", "down_proj"],    lora_alpha=64, lora_dropout=0, bias="none",    use_gradient_checkpointing="unsloth", random_state=42,)# GRPO: for each prompt, sample N responses, compute relative rewardsdef grpo_step(prompts, n_samples=8):    """Single GRPO update step."""    all_responses = []    all_rewards = []        for prompt in prompts:        responses = []        for _ in range(n_samples):            inputs = tokenizer(prompt, return_tensors="pt").to("cuda")            outputs = model.generate(                **inputs, max_new_tokens=MAX_SEQ_LENGTH,                do_sample=True, temperature=0.7, top_p=0.9,            )            response = tokenizer.decode(outputs[0][inputs.input_ids.shape[1]:], skip_special_tokens=True)            responses.append(response)                # Score responses (e.g., by length, complexity, or a reward model)        rewards = [min(len(r) / 100, 1.0) for r in responses]                # Group normalization: A_i = (r_i - mean(r)) / std(r)        mean_r = sum(rewards) / len(rewards)        std_r = math.sqrt(sum((r - mean_r)**2 for r in rewards) / len(rewards)) + 1e-8        advantages = [(r - mean_r) / std_r for r in rewards]                all_responses.extend(responses)        all_rewards.extend(advantages)        return all_responses, all_rewardsprint("GRPO training configured. Run with sufficient GPU memory.")model.save_pretrained(OUTPUT_DIR)tokenizer.save_pretrained(OUTPUT_DIR)print(f"GRPO model saved to {{OUTPUT_DIR}}")'''def generate_curriculum_script(model_config: Dict, data_dir: str, output_path: str) -> str:    """Generate curriculum learning script."""        return f'''#!/usr/bin/env python3"""NICTO Super Training v3.0 ΓÇö Stage 6: Curriculum LearningProgressively trains from easy ΓåÆ medium ΓåÆ hard ΓåÆ expert examples."""import json, os, torchos.environ["TOKENIZERS_PARALLELISM"] = "false"from unsloth import FastLanguageModel, is_bfloat16_supportedfrom unsloth.chat_templates import get_chat_template, train_on_responses_onlyfrom datasets import Datasetfrom transformers import TrainingArgumentsfrom trl import SFTTrainerDATA_DIR = "{data_dir.replace(chr(92), '/')}"OUTPUT_DIR = "{output_path.replace(chr(92), '/')}_curriculum"MAX_SEQ_LENGTH = {model_config["max_seq_length"]}LORA_R = {model_config["lora_r"]}BATCH_SIZE = {model_config["per_device_batch_size"]}GRAD_ACCUM = {model_config["gradient_accumulation_steps"]}LR = {model_config["learning_rate"]}def load_by_difficulty(difficulty):    """Load examples of a specific difficulty level."""    path = os.path.join(DATA_DIR, "super_v3_chatml.jsonl")    examples = []    with open(path, "r") as f:        for line in f:            if line.strip():                examples.append(json.loads(line))    # In real training, filter by difficulty metadata    return examplesdifficulty_levels = ["easy", "medium", "hard", "expert"]epochs_per_level = 1model, tokenizer = FastLanguageModel.from_pretrained(    model_name="{model_config["base_model"]}",    max_seq_length=MAX_SEQ_LENGTH,    dtype=torch.bfloat16 if is_bfloat16_supported() else torch.float16,    load_in_4bit=True,)tokenizer = get_chat_template(tokenizer, chat_template="chatml")model = FastLanguageModel.get_peft_model(    model, r=LORA_R,    target_modules=["q_proj", "k_proj", "v_proj", "o_proj",                    "gate_proj", "up_proj", "down_proj"],    lora_alpha=64, lora_dropout=0, bias="none",    use_gradient_checkpointing="unsloth", random_state=42,)def format_func(examples):    texts = []    for msg_list in examples["messages"]:        text = ""        for msg in msg_list:            text += f"<|im_start|>{{msg['role']}}\\n{{msg['content']}}<|im_end|>\\n"        text += "<|im_start|>assistant\\n"        texts.append(text)    return {{"text": texts}}for level, difficulty in enumerate(difficulty_levels):    print(f"\\n=== CURRICULUM LEVEL {{level}}: {{difficulty.upper()}} ===")    examples = load_by_difficulty(difficulty)    dataset = Dataset.from_list(examples).map(format_func, batched=True)        trainer = SFTTrainer(        model=model, tokenizer=tokenizer, train_dataset=dataset,        dataset_text_field="text", max_seq_length=MAX_SEQ_LENGTH,        dataset_num_proc=4, packing=False,        args=TrainingArguments(            per_device_train_batch_size=BATCH_SIZE,            gradient_accumulation_steps=GRAD_ACCUM,            warmup_steps=5,            num_train_epochs=epochs_per_level,            learning_rate=LR / (level + 1),  # Decay LR for later levels            fp16=not is_bfloat16_supported(),            bf16=is_bfloat16_supported(),            logging_steps=1,            optim="adamw_8bit",            weight_decay=0.01,            lr_scheduler_type="cosine",            seed=42,            output_dir=f"{{OUTPUT_DIR}}_level_{{level}}",            report_to="none",        ),    )    trainer = train_on_responses_only(trainer, "<|im_start|>user\\n", "<|im_start|>assistant\\n")    trainer.train()model.save_pretrained(OUTPUT_DIR)tokenizer.save_pretrained(OUTPUT_DIR)print(f"\\nCurriculum model saved to {{OUTPUT_DIR}}")'''# ΓöÇΓöÇΓöÇ Full Multi-Stage Pipeline ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef generate_full_pipeline(model_config: Dict, data_path: str, output_path: str) -> str:    """Generate a complete multi-stage training script (SFT ΓåÆ DPO ΓåÆ GRPO)."""        return f'''#!/usr/bin/env python3"""NICTO Super Training v3.0 ΓÇö FULL PIPELINE: SFT ΓåÆ DPO ΓåÆ GRPOThis script runs all stages sequentially for maximum capability."""import json, os, subprocess, sys, timeSTAGES = [    {{"name": "Stage 1: SFT (Supervised Fine-Tuning)", "script": "sft", "epochs": 3}},    {{"name": "Stage 2: DPO (Direct Preference Optimization)", "script": "dpo", "epochs": 2}},    {{"name": "Stage 3: GRPO (Group Relative Policy Optimization)", "script": "grpo", "epochs": 1}},]DATA_PATH = "{data_path.replace(chr(92), '/')}"OUTPUT_DIR = "{output_path.replace(chr(92), '/')}"for i, stage in enumerate(STAGES):    print(f"\\n{'='*70}")    print(f"  {{stage['name']}}")    print(f"{'='*70}")        stage_script = f"nicto_train_stage_{{stage['script']}}.py"    result = subprocess.run(        [sys.executable, stage_script,         "--data", DATA_PATH,         "--output", f"{{OUTPUT_DIR}}_stage_{{i}}",         "--epochs", str(stage['epochs'])],        capture_output=True, text=True,    )    print(result.stdout)    if result.returncode != 0:        print(f"ERROR in stage {{i}}: {{result.stderr}}")        sys.exit(1)        # Link output to next stage's input    os.symlink(f"{{OUTPUT_DIR}}_stage_{{i}}_merged", f"{{OUTPUT_DIR}}_checkpoint_{{i}}")print(f"\\n{'='*70}")print(f"  NICTO SUPER TRAINING v3.0 COMPLETE")print(f"  Final model: {{OUTPUT_DIR}}_stage_2_merged")print(f"{'='*70}")'''# ΓöÇΓöÇΓöÇ Continuous Improvement Engine ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef generate_continuous_improvement_script(model_config: Dict, data_path: str, output_path: str) -> str:    """Generate continuous self-improvement loop script."""        return f'''#!/usr/bin/env python3"""NICTO Super Training v3.0 ΓÇö Stage 7: Continuous Self-ImprovementAuto-detects weaknesses, generates targeted training data, and fine-tunes.Runs in a loop for perpetual improvement."""import json, os, subprocess, sys, timefrom pathlib import PathBASE_MODEL = "{output_path.replace(chr(92), '/')}_merged"OUTPUT_DIR = "{output_path.replace(chr(92), '/')}_continuous"DATA_DIR = "{data_path.replace(chr(92), '/')}"IMPROVEMENT_INTERVAL = 3600  # 1 hourdef assess_model():    """Run evaluation to find weak areas."""    # In practice: run benchmark suite, find domains with low scores    return {{        "weak_domains": ["advanced_mathematics", "quantum_physics", "rare_languages"],        "overall_score": 0.85,        "scores_by_domain": {{"mathematics": 0.92, "physics": 0.88, "programming": 0.95}},    }}def generate_targeted_data(weak_domains, count_per_domain=1000):    """Generate training data targeting weak domains."""    # Calls build_super_data_v3.py with specific domains    examples = []    for domain in weak_domains:        for i in range(count_per_domain):            examples.append({{                "messages": [                    {{"role": "system", "content": f"Expert knowledge about {{domain}}."}},                    {{"role": "user", "content": f"Explain {{domain}} in detail."}},                    {{"role": "assistant", "content": f"Deep knowledge about {{domain}}. Key concepts include..."}},                ]            }})    return examplesdef fine_tune(model_path, data, output_path):    """Run SFT on targeted data."""    from unsloth import FastLanguageModel, is_bfloat16_supported    from unsloth.chat_templates import get_chat_template, train_on_responses_only    from datasets import Dataset    from transformers import TrainingArguments    from trl import SFTTrainer        model, tokenizer = FastLanguageModel.from_pretrained(        model_name=model_path,        max_seq_length=8192,        dtype=torch.bfloat16 if is_bfloat16_supported() else torch.float16,        load_in_4bit=True,    )    tokenizer = get_chat_template(tokenizer, chat_template="chatml")        model = FastLanguageModel.get_peft_model(        model, r=16,        target_modules=["q_proj", "k_proj", "v_proj", "o_proj",                        "gate_proj", "up_proj", "down_proj"],        lora_alpha=32, lora_dropout=0, bias="none",        use_gradient_checkpointing="unsloth", random_state=42,    )        dataset = Dataset.from_list(data)    trainer = SFTTrainer(        model=model, tokenizer=tokenizer, train_dataset=dataset,        dataset_text_field="text", max_seq_length=8192,        dataset_num_proc=4, packing=False,        args=TrainingArguments(            per_device_train_batch_size=2,            gradient_accumulation_steps=8,            warmup_steps=5,            num_train_epochs=1,            learning_rate=1e-4,            fp16=not is_bfloat16_supported(),            bf16=is_bfloat16_supported(),            logging_steps=1,            output_dir=output_path,            report_to="none",        ),    )    trainer.train()    model.save_pretrained(output_path)    tokenizer.save_pretrained(output_path)    return output_pathdef cycle(iteration):    """Run one complete improvement cycle."""    print(f"\\n{'='*70}")    print(f"  CONTINUOUS IMPROVEMENT ΓÇö CYCLE {{iteration}}")    print(f"{'='*70}")        # 1. Assess current capabilities    assessment = assess_model()    print(f"\\nCurrent score: {{assessment['overall_score']:.2%}}")    print(f"Weak domains: {{assessment['weak_domains']}}")        if not assessment['weak_domains']:        print("All domains mastered! Sleeping...")        time.sleep(IMPROVEMENT_INTERVAL)        return        # 2. Generate targeted data for weak domains    data = generate_targeted_data(assessment['weak_domains'])    print(f"Generated {{len(data)}} targeted examples")        # 3. Fine-tune on targeted data    cycle_output = f"{{OUTPUT_DIR}}_cycle_{{iteration}}"    fine_tune(BASE_MODEL, data, cycle_output)    print(f"Cycle {{iteration}} improvement complete -> {{cycle_output}}")if __name__ == "__main__":    iteration = 1    while True:        cycle(iteration)        iteration += 1        time.sleep(IMPROVEMENT_INTERVAL)'''# ΓöÇΓöÇΓöÇ Main CLI ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇdef main():    import argparse        parser = argparse.ArgumentParser(description="NICTO Super Training v3.0 ΓÇö Multi-Stage Pipeline")    parser.add_argument("--mode", choices=["info", "sft", "dpo", "grpo", "curriculum",                                             "pipeline", "continuous", "export"],                        default="info", help="Training mode")    parser.add_argument("--model", default="qwen-32b", help=f"Model key: {', '.join(FRONTIER_MODELS.keys())}")    parser.add_argument("--data", default=None, help="Path to training data (JSONL)")    parser.add_argument("--output", default=None, help="Output directory")    parser.add_argument("--epochs", type=int, default=3, help="Training epochs")    parser.add_argument("--batch-size", type=int, default=2, help="Per-device batch size")    parser.add_argument("--lr", type=float, default=2e-4, help="Learning rate")    parser.add_argument("--export-type", choices=["sft", "dpo", "grpo", "curriculum", "pipeline", "continuous", "all"],                        default="all", help="Script type to export")    args = parser.parse_args()        # Resolve model config    if args.model not in FRONTIER_MODELS and args.model not in ("auto", "cpu"):        print(f"Unknown model: {args.model}. Available: {list(FRONTIER_MODELS.keys())}")        sys.exit(1)        model_config = dict(DEFAULT_CONFIG)    if args.model in FRONTIER_MODELS:        model_config["base_model"] = FRONTIER_MODELS[args.model]["repo"]        # Update with CLI overrides    model_config["num_train_epochs"] = args.epochs    model_config["per_device_batch_size"] = args.batch_size    model_config["learning_rate"] = args.lr        data_path = args.data or str(HERE / "training_data" / "super_v3_chatml.jsonl")    output_path = args.output or str(OUTPUT_DIR / "nicto_super_v3")        os.makedirs(CLOUD_DIR, exist_ok=True)    os.makedirs(REPORT_DIR, exist_ok=True)        if args.mode == "info":        total_params = FRONTIER_MODELS.get(args.model, {}).get("params", "N/A")        min_vram = FRONTIER_MODELS.get(args.model, {}).get("min_vram_gb", "N/A")        print(f"\n{'='*70}")        print(f"  NICTO SUPER TRAINING v3.0")        print(f"{'='*70}")        print(f"\n  Selected Model: {args.model}")        print(f"  Parameters: {total_params}")        print(f"  Min VRAM: {min_vram} GB")        print(f"  Training data: {data_path}")        print(f"  Output: {output_path}")        print(f"\n  Available modes:")        print(f"    info         - Show this info")        print(f"    export       - Export training scripts for cloud GPU")        print(f"    sft          - Supervised Fine-Tuning")        print(f"    dpo          - Direct Preference Optimization")        print(f"    grpo         - Group Relative Policy Optimization")        print(f"    curriculum   - Progressive curriculum training")        print(f"    pipeline     - Full SFT ΓåÆ DPO ΓåÆ GRPO pipeline")        print(f"    continuous   - Continuous self-improvement loop")        print(f"\n  Frontier models supported:")        for key, m in FRONTIER_MODELS.items():            print(f"    {key:20s} {m['name']:25s} {m['params']:20s} {m['min_vram_gb']}GB VRAM")        print()        return    if args.mode == "export":        # Replace any remaining Unicode chars that fail on Windows cp1252        def safe(text):            return text.replace('\u2014', '-').replace('\u2192', '->')                exporters = {            "sft": ("nicto_train_stage_sft.py", safe(generate_sft_script(model_config, data_path, output_path))),            "dpo": ("nicto_train_stage_dpo.py", safe(generate_dpo_script(model_config, data_path, output_path))),            "grpo": ("nicto_train_stage_grpo.py", safe(generate_grpo_script(model_config, output_path))),            "curriculum": ("nicto_train_stage_curriculum.py", safe(generate_curriculum_script(model_config, str(HERE / "training_data"), output_path))),            "pipeline": ("nicto_train_pipeline.py", safe(generate_full_pipeline(model_config, data_path, output_path))),            "continuous": ("nicto_train_continuous.py", safe(generate_continuous_improvement_script(model_config, data_path, output_path))),        }                if args.export_type == "all":            for fname, script in exporters.values():                path = CLOUD_DIR / fname                with open(path, "w", encoding="utf-8") as f:                    f.write(script)                print(f"  {path}")        else:            fname, script = exporters[args.export_type]            path = CLOUD_DIR / fname            with open(path, "w", encoding="utf-8") as f:                f.write(script)            print(f"  Exported: {path}")                print(f"\n  Scripts saved to {CLOUD_DIR}")        print(f"  Upload to cloud GPU (RunPod, Lambda, Colab) and run.")        return        print(f"Mode '{args.mode}' requires cloud GPU deployment.")    print(f"Run with --mode export to generate training scripts.")if __name__ == "__main__":    main()